template:
mod back_of_house {
    pub struct Breakfast {
        pub toast: String,
        seasonal_fruit: String,
    }

    impl Breakfast {
        pub fn summer(toast: &str) -> Breakfast {
            Breakfast {
                toast: String::from(toast),
                seasonal_fruit: String::from("peaches"),
            }
        }
    }

    pub enum DietaryBreakfast {
        Standard,
        Vegan,
        GlutenFree,
    }
}

[[SLOT use_breakfast]]
[[SLOT use_alias]]

pub fn order_breakfast() -> String {
    let mut meal = [[SLOT summer_call]];
    meal.toast = String::from("Wheat");
    meal.toast
}

pub fn describe_diet(diet: DietBreakfast) -> &'static str {
    match diet {
        DietBreakfast::Standard => "Standard breakfast with eggs and toast",
        DietBreakfast::Vegan => "Plant-based breakfast with tofu scramble",
        DietBreakfast::GlutenFree => "Gluten-free breakfast with rice cakes",
    }
}
